import React, { useState } from "react";
import { motion } from "framer-motion";
import {
  Star,
  Heart,
  Users,
  Sparkles,
  ChevronRight,
  Award,
  Zap,
  Music,
} from "lucide-react";
import { Link } from "react-router-dom";

const eventServices = [
  {
    id: 1,
    title: "Wedding Sangeet",
    icon: Heart,
    tagline: "Cinematic Choreography for Your Special Day",
    image:
      "https://images.unsplash.com/photo-1519671482749-fd09be7ccebf?auto=format&fit=crop&w=800&q=80",
    desc: "Transform your wedding celebration into an unforgettable visual spectacle with our bespoke choreography.",
    features: [
      "Couples choreography",
      "Family group performances",
      "Thematic concepts",
      "Professional dancers",
      "Full production support",
    ],
    highlights:
      "We create cinematic moments that tell your love story through dance. From intimate couple dances to grand ensemble performances, every move is tailored to your vision.",
    pricing: "Custom quotes",
  },
  {
    id: 2,
    title: "Corporate Events",
    icon: Users,
    tagline: "Elevate Your Brand Presence",
    image:
      "https://images.unsplash.com/photo-1552664730-d307ca884978?auto=format&fit=crop&w=800&q=80",
    desc: "Professional performances for product launches, award nights, and corporate galas.",
    features: [
      "Product launch performances",
      "Team building activities",
      "Flash mob experiences",
      "Brand storytelling",
      "Technical production",
    ],
    highlights:
      "Impress your audience with high-energy, sophisticated performances that align perfectly with your brand message and corporate values.",
    pricing: "Custom quotes",
  },
  {
    id: 3,
    title: "Music Videos & Production",
    icon: Sparkles,
    tagline: "Professional Artistic Direction",
    image:
      "https://images.unsplash.com/photo-1514525253161-7a46d19cd819?auto=format&fit=crop&w=800&q=80",
    desc: "Stage shows, music videos, and cinematic choreography for professional productions.",
    features: [
      "Music video choreography",
      "TV production",
      "Theater shows",
      "Concert performances",
      "Post-production consultation",
    ],
    highlights:
      "From concept to final cut, we bring professional-grade choreography to your creative vision with expertise in camera angles, timing, and artistic direction.",
    pricing: "Custom quotes",
  },
  {
    id: 4,
    title: "Private Sessions",
    icon: Award,
    tagline: "One-on-One Professional Coaching",
    image:
      "https://images.unsplash.com/photo-1534294-4f3d1f1a0a4b?auto=format&fit=crop&w=800&q=80",
    desc: "Personalized choreography and performance coaching for individuals and small groups.",
    features: [
      "Custom choreography",
      "Performance coaching",
      "Technical refinement",
      "Flexible scheduling",
      "One-on-one attention",
    ],
    highlights:
      "Get dedicated expert guidance tailored to your unique needs, whether preparing for an audition, event, or perfecting your craft.",
    pricing: "Custom quotes",
  },
];

const fitnessServices = [
  {
    id: 5,
    title: "Zumba Classes",
    icon: Zap,
    tagline: "Fun, High-Energy Dance Fitness",
    image:
      "https://images.unsplash.com/photo-1534294-4f3d1f1a0a4b?auto=format&fit=crop&w=800&q=80",
    desc: "Experience the thrill of Zumba - Latin-inspired dance fitness that burns calories while having fun.",
    features: [
      "All-level classes",
      "Latin rhythms",
      "Full-body cardio workout",
      "Group energy",
      "Flexible scheduling",
    ],
    highlights:
      "Zumba is not just a workout, it's a party! Our certified instructors create an infectious atmosphere where you'll dance, sweat, and smile. Perfect for all fitness levels.",
    pricing: "₹500/class or ₹3000/month",
  },
  {
    id: 6,
    title: "Bollywood Dance Fitness",
    icon: Music,
    tagline: "Groove to Bollywood Beats",
    image:
      "https://images.unsplash.com/photo-1524594684888-c55847b4b629?auto=format&fit=crop&w=800&q=80",
    desc: "Learn iconic Bollywood moves while getting a complete cardio and strength training workout.",
    features: [
      "Bollywood choreography",
      "Cardio conditioning",
      "Popular movie songs",
      "Beginner-friendly",
      "Social fitness community",
    ],
    highlights:
      "Dance to your favorite Bollywood hits while toning your body. Our instructors break down complex moves into easy steps, making it accessible and fun for everyone.",
    pricing: "₹500/class or ₹3000/month",
  },
  {
    id: 7,
    title: "Hip Hop & Urban Dance",
    icon: Sparkles,
    tagline: "Express Yourself with Urban Beats",
    image:
      "https://images.unsplash.com/photo-1506157786151-b8491531f063?auto=format&fit=crop&w=800&q=80",
    desc: "Master contemporary urban dance styles with street credibility and modern choreography.",
    features: [
      "Contemporary styles",
      "Hip hop basics to advanced",
      "Freestyle sessions",
      "Performance opportunities",
      "Cool community",
    ],
    highlights:
      "Express your individuality through hip hop and urban dance. From street jazz to popping, we cover diverse styles with professional instruction and a supportive community.",
    pricing: "₹500/class or ₹3000/month",
  },
  {
    id: 8,
    title: "Aerobic Dance Fitness",
    icon: Heart,
    tagline: "Dance Your Way to Fitness",
    image:
      "https://images.unsplash.com/photo-1461896836934-ffe607ba8211?auto=format&fit=crop&w=800&q=80",
    desc: "High-intensity aerobic sessions combining dance movements with cardio exercises.",
    features: [
      "High-energy workouts",
      "Weight loss focus",
      "Strength training",
      "Music-driven classes",
      "Progress tracking",
    ],
    highlights:
      "Burn calories, build endurance, and improve your overall fitness while dancing to energetic beats. Our trainers create personalized fitness plans for your goals.",
    pricing: "₹500/class or ₹3000/month",
  },
];

const ProServices = () => {
  const [activeService, setActiveService] = useState(null);
  const [activeCategory, setActiveCategory] = useState("events");

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15,
        delayChildren: 0.2,
      },
    },
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 40 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6 },
    },
  };

  const currentServices =
    activeCategory === "events" ? eventServices : fitnessServices;

  return (
    <div className="pt-24 pb-24 px-6 lg:px-12 overflow-hidden">
      {/* Decorative Backgrounds */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute top-0 right-0 w-96 h-96 bg-gold/3 rounded-full blur-3xl" />
        <div className="absolute bottom-1/3 left-0 w-96 h-96 bg-gold/2 rounded-full blur-3xl" />
      </div>

      {/* Header Section */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center"
        >
          <p className="text-gold tracking-[0.4em] uppercase text-xs font-montserrat font-light mb-4">
            Professional Services
          </p>
          <h1 className="text-5xl md:text-6xl lg:text-7xl font-cinzel font-bold mb-8">
            Our Services
          </h1>
          <div className="h-1 w-40 bg-gradient-to-r from-transparent via-gold to-transparent mx-auto mb-8" />
          <p className="max-w-3xl mx-auto text-ivory/70 text-lg font-light leading-relaxed">
            Elevate your special moments with world-class choreography and
            artistic direction. From premium events to transformative fitness
            experiences, we bring professional excellence to every engagement.
          </p>
        </motion.div>
      </section>

      {/* Category Toggle */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="flex justify-center gap-4"
        >
          {[
            { id: "events", label: "Events & Productions" },
            { id: "fitness", label: "Fitness Classes" },
          ].map((category) => (
            <motion.button
              key={category.id}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => {
                setActiveCategory(category.id);
                setActiveService(null);
              }}
              className={`px-8 py-4 rounded-full font-cinzel uppercase tracking-widest text-sm font-bold transition-all duration-300 border-2 ${
                activeCategory === category.id
                  ? "bg-gold text-charcoal border-gold shadow-lg shadow-gold/30"
                  : "text-gold border-gold/40 hover:border-gold/80 bg-transparent hover:bg-gold/5"
              }`}
            >
              {category.label}
            </motion.button>
          ))}
        </motion.div>
      </section>

      {/* Services Grid */}
      <section className="max-w-7xl mx-auto mb-24">
        <motion.div
          key={activeCategory}
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="grid md:grid-cols-2 gap-8"
        >
          {currentServices.map((service) => {
            const Icon = service.icon;
            const isActive = activeService === service.id;

            return (
              <motion.div
